#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e5+5;
struct SegTree{LL sum;int ls,rs;}t[N*30];
int n,Cnt,a[N],Rt[N];
LL Ls[N],cnt,Ans;
int lg2[N],st[N][20];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Insert(int pre,int &u,int l,int r,int k){
    u=(++Cnt),t[u]=t[pre],t[u].sum++;
    if(l==r)return;int mid=(l+r)>>1;
    if(k<=mid)Insert(t[pre].ls,t[u].ls,l,mid,k);
    else Insert(t[pre].rs,t[u].rs,mid+1,r,k);return;
}
LL Ask(int pre,int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return t[u].sum-t[pre].sum;
    int mid=(l+r)>>1;LL res=0;
    if(L<=mid)res+=Ask(t[pre].ls,t[u].ls,l,mid,L,R);
    if(R>mid)res+=Ask(t[pre].rs,t[u].rs,mid+1,r,L,R);
    return res;
}
void init_ST(){
    for(int i=2;i<=n;i++)lg2[i]=lg2[i/2]+1;
    for(int i=1;i<=n;i++)st[i][0]=i;
    for(int j=1;(1<<j)<=n;j++)
        for(int i=1;i+(1<<j)-1<=n;i++){
            int x=st[i][j-1],y=st[i+(1<<j-1)][j-1];
            st[i][j]=(a[x]>=a[y]?x:y);
        }
    return;
}
int query(int l,int r){
    int k=lg2[r-l+1];
    int x=st[l][k],y=st[r-(1<<k)+1][k];
    return (a[x]>=a[y]?x:y);
}
void CDQsolve(int l,int r){
    if(l>r)return;
    if(l==r){Ans+=(Ls[a[l]]==1);return;}
    int mid=query(l,r);
    if(mid-l+1<=r-mid){//左边数更少
        for(int i=l;i<=mid;i++){
            int num=Ls[a[mid]]/Ls[a[i]];
            int k=upper_bound(Ls+1,Ls+cnt+1,num)-Ls-1;
            Ans+=Ask(Rt[mid-1],Rt[r],1,cnt,1,k);
        }
    }else{//右边数更少
        for(int i=mid;i<=r;i++){
            int num=Ls[a[mid]]/Ls[a[i]];
            int k=upper_bound(Ls+1,Ls+cnt+1,num)-Ls-1;
            Ans+=Ask(Rt[l-1],Rt[mid],1,cnt,1,k);
        }
    }CDQsolve(l,mid-1);CDQsolve(mid+1,r);return;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),Ls[++cnt]=a[i];
    sort(Ls+1,Ls+cnt+1);
    cnt=unique(Ls+1,Ls+cnt+1)-Ls-1;
    for(int i=1;i<=n;i++)
        a[i]=lower_bound(Ls+1,Ls+cnt+1,a[i])-Ls;
    for(int i=1;i<=n;i++)
        Insert(Rt[i-1],Rt[i],1,cnt,a[i]);
    init_ST();
    CDQsolve(1,n);cout<<Ans<<"\n";
    return 0;
}
